SELECT [VendutoCompratoProiezione-step10-new-pivot].*, IIf([pairssold]-[pairspurchased]-[pairsinventory]>0,[pairssold]-[pairspurchased]-[pairsinventory],0) AS toBuy, IIf([pairssold]-[pairspurchased]-[pairsinventory]<=0,[pairssold]-[pairspurchased]-[pairsinventory],0) AS toSell, IIf([ForecastedPairsByMarketCorrected_]-[pairspurchased]-[pairsinventory]>0,[ForecastedPairsByMarketCorrected_]-[pairspurchased]-[pairsinventory],0) AS toBuyByBudgetCorrected, IIf([ForecastedPairsByMarketCorrected_]-[pairspurchased]-[pairsinventory]<=0,[ForecastedPairsByMarketCorrected_]-[pairspurchased]-[pairsinventory],0) AS toSellByBudgetCorrected, IIf([ForecastedPairsFlat]-[pairspurchased]-[pairsinventory]>0,[ForecastedPairsFlat]-[pairspurchased]-[pairsinventory],0) AS toBuyFlat, IIf([ForecastedPairsFlat]-[pairspurchased]-[pairsinventory]<=0,[ForecastedPairsFlat]-[pairspurchased]-[pairsinventory],0) AS toSellFlat
FROM [VendutoCompratoProiezione-step10-new-pivot];

